patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..bee67b7a61b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1338,6 +1338,17 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

+  // Look through (X & Mask) pattern for range check idioms.
+  // (X & Mask) == C where C & Mask == C is equivalent to C <= X <= C + (~Mask).
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  if (V1 != V2) {
+    Value *X;
+    if (match(V1, m_And(m_Value(X), m_APInt(Mask1))))
+      V1 = X;
+    if (match(V2, m_And(m_Value(X), m_APInt(Mask2))))
+      V2 = X;
+  }
+
   if (V1 != V2)
     return nullptr;

@@ -1351,6 +1362,22 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

+  // If we have (X & Mask) == C where C & Mask == C, this is equivalent to
+  // C <= X <= C + (~Mask).
+  // For the OR case, we handle icmp eq (X & Mask), C.
+  // For the AND case, we handle icmp ne (X & Mask), C (which becomes eq after inversion).
+  if (Mask1 && ((IsAnd && Pred1 == ICmpInst::ICMP_NE) ||
+                (!IsAnd && Pred1 == ICmpInst::ICMP_EQ)) &&
+      (*C1 & *Mask1) == *C1) {
+    APInt Upper = *C1 + ~(*Mask1);
+    CR1 = ConstantRange(*C1, Upper + 1);
+  }
+  if (Mask2 && ((IsAnd && Pred2 == ICmpInst::ICMP_NE) ||
+                (!IsAnd && Pred2 == ICmpInst::ICMP_EQ)) &&
+      (*C2 & *Mask2) == *C2) {
+    APInt Upper = *C2 + ~(*Mask2);
+    CR2 = ConstantRange(*C2, Upper + 1);
+  }
   Type *Ty = V1->getType();
   Value *NewV = V1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);

